VALUES
  ('fire-eq-tech-moex-02670', 'fire-eq-tech', 'fire-eq-tech-moex-099-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「消防法施行細則」規定，下列敘述何者有誤？', '["於森林區域、森林保護區內引火者，引火人應於五日前向當地消防機關申請許可", "消防栓設置以採用地面下雙口式為原則，當地消防機關負責保養、維護消防栓", "施放以火藥及金屬粉末為主要原料，其成品直徑在七點五公分以上或射程在七十五公尺以上之煙火， 其負責人應將煙火種類、數量、施放時間、地點及有關防火、戒備、擬採措施，於三日前向當地消防 機關申請許可", "使用炸藥爆破施工，其負責人應填具爆炸物配購申請表，檢附生產計畫或工程圖說，需炸物體計算表 及登記許可證件，於五日前向當地消防機關申請許可"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "9095381f2ea9", "answer_pdf_sha1": "6722dd70c930", "source_family": "moex-gov-tw", "moex": {"exam_code": "099080", "c": "701", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "099", "exam_name": "099年專技消防設備人員、地政士、專責報關、保險人員、特考中醫、語言治療、聽力考試", "original_question_number": 22, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02671', 'fire-eq-tech', 'fire-eq-tech-moex-099-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「消防法施行細則」規定，下列總樓地板面積在三百平方公尺之供公眾使用建築物，何者可免遴用防 火管理人？', '["餐廳", "遊藝場", "補習班", "演藝場"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "9095381f2ea9", "answer_pdf_sha1": "6722dd70c930", "source_family": "moex-gov-tw", "moex": {"exam_code": "099080", "c": "701", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "099", "exam_name": "099年專技消防設備人員、地政士、專責報關、保險人員、特考中醫、語言治療、聽力考試", "original_question_number": 23, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02672', 'fire-eq-tech', 'fire-eq-tech-moex-099-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「防焰性能認證作業規定」防焰性能認證之申請人為從事防焰物品或其材料之裁剪、縫製、安裝業者 時，應經由直轄市、縣（市）消防機關向A單位申請，直轄市、縣（市）消防機關於受理申請案經調查 後，於B時間內附具調查意見表，連同申請書及其相關資料各C份送A單位審查，餘一份留存消防機關， 請問A，B，C為何？', '["A＝經濟部，B＝五日，C＝五", "A＝建設局，B＝十日，C＝三", "A＝內政部，B＝七日，C＝二", "A＝消防署，B＝一個月，C＝一"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "9095381f2ea9", "answer_pdf_sha1": "6722dd70c930", "source_family": "moex-gov-tw", "moex": {"exam_code": "099080", "c": "701", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "099", "exam_name": "099年專技消防設備人員、地政士、專責報關、保險人員、特考中醫、語言治療、聽力考試", "original_question_number": 24, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02673', 'fire-eq-tech', 'fire-eq-tech-moex-099-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「公共危險物品及可燃性高壓氣體設置標準暨安全管理辦法」之規定，設於室外之製造或處理液體六 類物品之設備，應在周圍設置距地面高度在多少公分以上之圍阻措施，或設置具有同等以上效能之防止 流出措施？', '["5", "10", "12", "15"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "9095381f2ea9", "answer_pdf_sha1": "6722dd70c930", "source_family": "moex-gov-tw", "moex": {"exam_code": "099080", "c": "701", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "099", "exam_name": "099年專技消防設備人員、地政士、專責報關、保險人員、特考中醫、語言治療、聽力考試", "original_question_number": 25, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02674', 'fire-eq-tech', 'fire-eq-tech-moex-099-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「建築法」有關工程圖樣及說明書規定，下列敘述何者有誤？', '["地盤圖，其比例尺不得小於一千分之一", "建築物之平面、立面圖，其比例尺不得小於二百分之一", "建築物之剖面圖，其比例尺不得小於二百分之一", "建築物各部之尺寸構造及材料，其比例尺不得小於三十分之一"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "9095381f2ea9", "answer_pdf_sha1": "6722dd70c930", "source_family": "moex-gov-tw", "moex": {"exam_code": "099080", "c": "701", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "099", "exam_name": "099年專技消防設備人員、地政士、專責報關、保險人員、特考中醫、語言治療、聽力考試", "original_question_number": 26, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02675', 'fire-eq-tech', 'fire-eq-tech-moex-099-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「建築法」規定，起造人於申請建造執照前，得先列舉建築有關事項，並檢附圖樣，繳納費用，申請 直轄市、縣（市）主管建築機關預為審查。自審定合格之日起多少個月內，依審定結果申請建造執照， 直轄市、縣（市）主管建築機關就其審定事項應予認可？', '["六", "九", "十二", "二十四"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "9095381f2ea9", "answer_pdf_sha1": "6722dd70c930", "source_family": "moex-gov-tw", "moex": {"exam_code": "099080", "c": "701", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "099", "exam_name": "099年專技消防設備人員、地政士、專責報關、保險人員、特考中醫、語言治療、聽力考試", "original_question_number": 27, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02676', 'fire-eq-tech', 'fire-eq-tech-moex-099-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「防焰性能試驗基準」規定，有關每平方公尺質量超過四五○公克經防焰性能認證審查合格之具熱收 縮性厚纖維製品，其材料之防焰性能，下列敘述何者正確？', '["餘焰時間不得超過十秒", "餘燃時間不得超過二十秒", "碳化面積不得超過五十平方公分", "碳化距離不得超過三十公分"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "9095381f2ea9", "answer_pdf_sha1": "6722dd70c930", "source_family": "moex-gov-tw", "moex": {"exam_code": "099080", "c": "701", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "099", "exam_name": "099年專技消防設備人員、地政士、專責報關、保險人員、特考中醫、語言治療、聽力考試", "original_question_number": 28, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02677', 'fire-eq-tech', 'fire-eq-tech-moex-099-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「液化石油氣容器定期檢驗基準」規定，供家庭或營業場所使用之二十公斤裝液化石油氣容器自個別 認可檢驗合格日起，十九年以上者之檢驗期限為何？', '["每五年檢驗一次", "每四年檢驗一次", "每三年檢驗一次", "每年檢驗一次"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "9095381f2ea9", "answer_pdf_sha1": "6722dd70c930", "source_family": "moex-gov-tw", "moex": {"exam_code": "099080", "c": "701", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "099", "exam_name": "099年專技消防設備人員、地政士、專責報關、保險人員、特考中醫、語言治療、聽力考試", "original_question_number": 29, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02678', 'fire-eq-tech', 'fire-eq-tech-moex-099-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「各類場所消防安全設備設置標準」有關水霧滅火設備規定，下列敘述何者有誤？', '["每一水霧噴頭之有效半徑在二點一公尺以下", "每一放射區域以五十平方公尺為原則", "放射區域在二區域以上者，應保持四十立方公尺以上之水源容量", "用於防護電氣設備者，核算管系最末端一個放射區域全部水霧噴頭放水壓力均能達每平方公分二點七 公斤以上或0.27 MPa 以上"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "9095381f2ea9", "answer_pdf_sha1": "6722dd70c930", "source_family": "moex-gov-tw", "moex": {"exam_code": "099080", "c": "701", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "099", "exam_name": "099年專技消防設備人員、地政士、專責報關、保險人員、特考中醫、語言治療、聽力考試", "original_question_number": 30, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02679', 'fire-eq-tech', 'fire-eq-tech-moex-099-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「避難器具支固器具及固定部之結構、強度計算及施工方法」有關袋長超過40公尺的斜降式救助袋之 下部支撐裝置固定在降落面的固定器具之構造、強度及埋設到降落面方法之規定，下列敘述何者有誤？', '["固定器具之固定環應為直徑15 mm以上之CNS 3270（不銹鋼棒）或具同等以上強度及耐蝕措施者", "固定部展開救助袋時，與降落面角度約為35度。另應設置於能讓袋子完全展開之避難空地上", "箱子與蓋子應具有能耐車輛等通行之積載荷重強度，且符合CNS 2472（灰口鑄鐵件）規定或具同等以 上耐蝕性能者", "固定環需確實埋入降落面，能承受750公斤之拉伸荷重，並應有防止固定環脫離之有效措施"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "9095381f2ea9", "answer_pdf_sha1": "6722dd70c930", "source_family": "moex-gov-tw", "moex": {"exam_code": "099080", "c": "701", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "099", "exam_name": "099年專技消防設備人員、地政士、專責報關、保險人員、特考中醫、語言治療、聽力考試", "original_question_number": 31, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL)
